import React from 'react';

interface UserCardProps {
  name: string;
  email: string;
  role: string;
  onMessage: () => void;
}

const UserCard: React.FC<UserCardProps> = ({ name, email, role, onMessage }) => {
  return (
    <div className="bg-gray-800 text-white rounded-xl p-6 shadow-md hover:shadow-lg transition-shadow">
      <div className="flex items-center gap-4 mb-4">
        <img
          src={`https://ui-avatars.com/api/?name=${name}&background=random`}
          alt={name}
          className="w-12 h-12 rounded-full"
        />
        <div>
          <h3 className="text-lg font-semibold">{name}</h3>
          <p className="text-gray-400 text-sm">{email}</p>
        </div>
      </div>
      <div className="flex justify-between items-center">
        <span className="text-sm bg-indigo-600 text-white px-3 py-1 rounded-full">{role}</span>
        <button
          onClick={onMessage}
          className="px-4 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-500 transition"
        >
          Message
        </button>
      </div>
    </div>
  );
};

export default UserCard;

