import React from 'react';
import { Bar } from 'react-chartjs-2';

interface StatisticsProps {
  totalSales: number;
  activeUsers: number;
  inventoryStatus: number;
}

const Statistics: React.FC<StatisticsProps> = ({ totalSales, activeUsers, inventoryStatus }) => {
  const data = {
    labels: ['Total Sales', 'Active Users', 'Inventory Status'],
    datasets: [
      {
        label: 'Metrics',
        data: [totalSales, activeUsers, inventoryStatus],
        backgroundColor: [
          'rgba(75, 192, 192, 0.6)',
          'rgba(54, 162, 235, 0.6)',
          'rgba(255, 206, 86, 0.6)'
        ],
        borderColor: [
          'rgba(75, 192, 192, 1)',
          'rgba(54, 162, 235, 1)',
          'rgba(255, 206, 86, 1)'
        ],
        borderWidth: 1
      }
    ]
  };

  return (
    <div className="bg-gray-800 text-white rounded-xl p-6 shadow-md">
      <h2 className="text-xl font-semibold mb-4">Dashboard Overview</h2>
      <Bar data={data} options={{ maintainAspectRatio: false }} />
    </div>
  );
};

export default Statistics;
